import{_ as n,c as s,o as p,R as a}from"./chunks/framework.CIzs38F0.js";const d=JSON.parse('{"title":"一、win下","description":"","frontmatter":{},"headers":[],"relativePath":"guide/Linux/vpn/6客户端使用.md","filePath":"guide/Linux/vpn/6客户端使用.md","lastUpdated":1701595065000}'),e={name:"guide/Linux/vpn/6客户端使用.md"},l=a(`<h1 id="一、win下" tabindex="-1">一、win下 <a class="header-anchor" href="#一、win下" aria-label="Permalink to &quot;一、win下&quot;">​</a></h1><blockquote><p>Vpn 使用教程</p><p><a href="https://openvpn.net/community-downloads/" target="_blank" rel="noreferrer">官方下载地址页面</a></p><p><a href="https://swupdate.openvpn.org/community/releases/openvpn-install-2.4.8-I602-Win7.exe" target="_blank" rel="noreferrer">openvpn-install-2.4.8-I602-Win7.exe</a></p><p><a href="https://swupdate.openvpn.org/community/releases/openvpn-install-2.4.8-I602-Win10.exe" target="_blank" rel="noreferrer">openvpn-install-2.4.8-I602-Win10.exe</a></p></blockquote><p>1, 双击 openvpn-2.2.2-install.exe 安装</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/1.jpg" alt="1安装"></p><p>2, 安装完后将 config 目录里的文件复制到 C:\\Program Files (x86)\\OpenVPN\\config 目录下</p><p>或者</p><ul><li><code>C:\\Program Files\\OpenVPN\\config</code></li><li><code>C:\\User\\用户名\\OpenVPN\\config</code>（通过双击ovpn的方式会把ovpn拷贝到这个目录</li></ul><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310200953510.jpg" alt="2安装"></p><p>3, 右击 openvpn 图标，点以管理员身份运行 （如果以普通用户运行则不能访问google）</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310200953440.jpg" alt="3安装"></p><p>4, 右击右下角 openvpn 图标，点 connect</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201028457.jpg" alt="4安装"></p><p>5, 右下角 openvpn 图标变绿说明已经连接成功，就可以开始使用</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201028655.jpg" alt="5安装"></p><h1 id="二、mac下" tabindex="-1">二、Mac下 <a class="header-anchor" href="#二、mac下" aria-label="Permalink to &quot;二、Mac下&quot;">​</a></h1><p>1，安装Tunnelblick【OpenVPN客户端】</p><blockquote><p>下载地址</p></blockquote><p><a href="https://tunnelblick.net/downloads.html" target="_blank" rel="noreferrer">https://tunnelblick.net/downloads.html</a></p><p>2，安装</p><ul><li></li></ul><p>安装应按照屏幕上的说明来进行。 完成以后会弹出如下框：</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201029628.png" alt="6安装"></p><p>点击[我没有配置文件]，弹出如下：</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201030306.png" alt="7安装"></p><p>点击[新建配置样本，并且进行编辑]，关闭所有弹出的对话框。在桌面出现一个配置样例</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201030160.png" alt="8安装"></p><p>安装过程结束</p><p>3,配置链接文件</p><p>管理员给你的所有关于VPN的链接配置文件放入到桌面的样子文件夹中：</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201030711.jpg" alt="2安装"></p><p>重命名桌面文件的名字为：xxx.tblk.[重命名后的文件必须用.tblk结尾</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201030032.png" alt="7安装"></p><p>点击添加。 然后双击xxx.tblk文件：</p><p>或者下载其他方式:</p><p><a href="https://openvpn.net/downloads/openvpn-connect-v2-macos.dmg" target="_blank" rel="noreferrer">OpenVPN Connect Client for macOS version 2.7.1.100</a></p><h1 id="三、手机下" tabindex="-1">三、手机下 <a class="header-anchor" href="#三、手机下" aria-label="Permalink to &quot;三、手机下&quot;">​</a></h1><p>一、苹果手机VPN配置使用说明</p><p>1、在手机设置中，找到“通用”设置，进去后找“VPN”</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201031615.png" alt="vpnmac1"></p><p>2、添加 VPN配置，在“类型”选项，选择“L2TP”，点击“添加配置”返回配置页面</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032604.png" alt="vpnmac2"></p><p>3、按以下画面输入配置信息,服务器地址为：113.106.111.3，</p><p>账户是教职工校园无线上网账号，密码是无线账号的密码，密钥是20个0，最后点击“完成”</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032435.png" alt="vpnmac3"></p><p>4、 回到“设置”设置界面，打开“VPN”开关连接，成功后，状态栏会显示VPN图标</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032172.png" alt="vpnmac4"></p><ul><li>二、安卓系统VPN配置使用说明</li></ul><p>1、在手机设置中，找到VPN设置</p><p>2、新建VPN连接，服务器地址为113.106.111.3，连接类型为PPTP，不需PPP（MPPE）加密</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032071.png" alt="vpnmac5"></p><p>3、输入远程无线上网用账号和密码，点击连接</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032980.png" alt="vpnmac6"></p><p>4、连接成功后，状态栏会显示VPN图标</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032147.png" alt="vpnmac7"></p><p>三、断开“VPN连接”。</p><p>1、如不需再处理OA文件，需要将VPN断开，状态栏上的VPN图标消失，以免影响其他上网</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202310201032043.png" alt="vpnmac8"></p><h1 id="四、linux下" tabindex="-1">四、Linux下 <a class="header-anchor" href="#四、linux下" aria-label="Permalink to &quot;四、Linux下&quot;">​</a></h1><p>以CentOS-7.7，</p><ul><li>client端</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">yum install -y openvpn</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">#启动</span></span>
<span class="line"><span style="color:#e1e4e8;">openvpn \\</span></span>
<span class="line"><span style="color:#e1e4e8;">--daemon \\</span></span>
<span class="line"><span style="color:#e1e4e8;">--cd /etc/openvpn \\</span></span>
<span class="line"><span style="color:#e1e4e8;">--config client.ovpn \\</span></span>
<span class="line"><span style="color:#e1e4e8;">--log-append /var/log/openvpn.log \\</span></span>
<span class="line"><span style="color:#e1e4e8;">--auth-nocache</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">或者</span></span>
<span class="line"><span style="color:#e1e4e8;">yum install openvpn</span></span>
<span class="line"><span style="color:#e1e4e8;">cp client.ovpn /etc/openvpn/client.conf #一定要复制到这里</span></span>
<span class="line"><span style="color:#e1e4e8;">openvpn --client --config /etc/openvpn/client.conf #测试一下</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">yum install -y openvpn</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">#启动</span></span>
<span class="line"><span style="color:#24292e;">openvpn \\</span></span>
<span class="line"><span style="color:#24292e;">--daemon \\</span></span>
<span class="line"><span style="color:#24292e;">--cd /etc/openvpn \\</span></span>
<span class="line"><span style="color:#24292e;">--config client.ovpn \\</span></span>
<span class="line"><span style="color:#24292e;">--log-append /var/log/openvpn.log \\</span></span>
<span class="line"><span style="color:#24292e;">--auth-nocache</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">或者</span></span>
<span class="line"><span style="color:#24292e;">yum install openvpn</span></span>
<span class="line"><span style="color:#24292e;">cp client.ovpn /etc/openvpn/client.conf #一定要复制到这里</span></span>
<span class="line"><span style="color:#24292e;">openvpn --client --config /etc/openvpn/client.conf #测试一下</span></span></code></pre></div>`,61),o=[l];function c(t,i,r,g,h,m){return p(),s("div",null,o)}const v=n(e,[["render",c]]);export{d as __pageData,v as default};
